				ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
				temp2 = d_in2_pad_cumv[pad_base + ori_col * common.in2_pad_cumv_rows + ori_row];

				d_in2_sub_cumh[sub_base + col * common.in2_sub_cumh_rows + row] = temp - temp2;
			}
		}

		for(ei_new = 0; ei_new < common.in2_sub_cumh_rows; ei_new++){

			pos_ori = sub_base + ei_new;

			sum = 0.0f;
			for(position = pos_ori; position < pos_ori + common.in2_sub_cumh_elem; position = position + common.in2_sub_cumh_rows){
				d_in2_sub_cumh[position] = d_in2_sub_cumh[position] + sum;
				sum = d_in2_sub_cumh[position];
			}
		}

		for(col = 0; col < common.in2_sub2_cols; col++){
			for(row = 0; row < common.in2_sub2_rows; row++){

				ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel_collow - 1;
				temp = d_in2_sub_cumh[sub_base + ori_col * common.in2_sub_cumh_rows + ori_row];

				ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
				temp2 = d_in2_sub_cumh[sub_base + ori_col * common.in2_sub_cumh_rows + ori_row];

				temp2 = temp - temp2;

				d_in2_sub2[sub2_base + col * common.in2_sub2_rows + row] = temp2 * temp2;

				d_conv[conv_base + col * common.in2_sub2_rows + row] =
					d_conv[conv_base + col * common.in2_sub2_rows + row] -
					temp2 * in_final_sum / (fp)common.in_elem;
			}
		}

		for(col = 0; col < common.in2_pad_cumv_cols; col++){
			for(row = 0; row < common.in2_pad_cumv_rows; row++){

				if(row > (common.in2_pad_add_rows - 1) &&
				   row < (common.in2_pad_add_rows + common.in2_rows) &&
				   col > (common.in2_pad_add_cols - 1) &&
				   col < (common.in2_pad_add_cols + common.in2_cols)){
					ori_row = row - common.in2_pad_add_rows;
					ori_col = col - common.in2_pad_add_cols;
					d_in2_pad_cumv[pad_base + col * common.in2_pad_cumv_rows + row] =
						d_in2_sqr[in2_sqr_base + ori_col * common.in2_rows + ori_row];
				}
				else{
					d_in2_pad_cumv[pad_base + col * common.in2_pad_cumv_rows + row] = 0.0f;
				}
			}
		}

		for(ei_new = 0; ei_new < common.in2_pad_cumv_cols; ei_new++){

			pos_ori = pad_base + ei_new * common.in2_pad_cumv_rows;

			sum = 0.0f;
			for(position = pos_ori; position < pos_ori + common.in2_pad_cumv_rows; position = position + 1){
				d_in2_pad_cumv[position] = d_in2_pad_cumv[position] + sum;
				sum = d_in2_pad_cumv[position];
			}
		}

		for(col = 0; col < common.in2_sub_cumh_cols; col++){
			for(row = 0; row < common.in2_sub_cumh_rows; row++){

				ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
				ori_col = col + common.in2_pad_cumv_sel_collow - 1;
				temp = d_in2_pad_cumv[pad_base + ori_col * common.in2_pad_cumv_rows + ori_row];

				ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
				ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
				temp2 = d_in2_pad_cumv[pad_base + ori_col * common.in2_pad_cumv_rows + ori_row];

				d_in2_sub_cumh[sub_base + col * common.in2_sub_cumh_rows + row] = temp - temp2;
			}
		}

		for(ei_new = 0; ei_new < common.in2_sub_cumh_rows; ei_new++){

			pos_ori = sub_base + ei_new;

			sum = 0.0f;
			for(position = pos_ori; position < pos_ori + common.in2_sub_cumh_elem; position = position + common.in2_sub_cumh_rows){
				d_in2_sub_cumh[position] = d_in2_sub_cumh[position] + sum;
				sum = d_in2_sub_cumh[position];
			}
		}

		for(col = 0; col < common.conv_cols; col++){
			for(row = 0; row < common.conv_rows; row++){

				ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel_collow - 1;
				temp = d_in2_sub_cumh[sub_base + ori_col * common.in2_sub_cumh_rows + ori_row];

				ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
				temp2 = d_in2_sub_cumh[sub_base + ori_col * common.in2_sub_cumh_rows + ori_row];

				temp2 = temp - temp2;

				d_in2_sqr_sub2[in2_sqr_sub2_base + col * common.conv_rows + row] = temp2;

				temp2 = temp2 - (d_in2_sub2[sub2_base + col * common.conv_rows + row] / (fp)common.in_elem);

				if(temp2 < 0.0f){
					temp2 = 0.0f;
				}
				temp2 = sqrt(temp2);

				temp2 = denomT * temp2;

				d_conv[conv_base + col * common.conv_rows + row] =
					d_conv[conv_base + col * common.conv_rows + row] / temp2;
			}
		}

		cent = common.sSize + common.tSize + 1;
		pointer = frame_no - 1 + point_no * common.no_frames;
		tMask_row = cent + d_tRowLoc[pointer] - d_Row[point_no] - 1;
		tMask_col = cent + d_tColLoc[pointer] - d_Col[point_no] - 1;

		for(ei_new = 0; ei_new < common.tMask_elem; ei_new++){
			d_tMask[tMask_base + ei_new] = 0.0f;
		}
		d_tMask[tMask_base + tMask_col * common.tMask_rows + tMask_row] = 1.0f;

		for(col = 1; col <= common.mask_conv_cols; col++){

			j = col + common.mask_conv_joffset;
			jp1 = j + 1;
			if(common.mask_cols < jp1){
				ja1 = jp1 - common.mask_cols;
			}
			else{
				ja1 = 1;
			}
			if(common.tMask_cols < j){
				ja2 = common.tMask_cols;
			}
			else{
				ja2 = j;
			}

			for(row = 1; row <= common.mask_conv_rows; row++){

				i = row + common.mask_conv_ioffset;
				ip1 = i + 1;

				if(common.mask_rows < ip1){
					ia1 = ip1 - common.mask_rows;
				}
				else{
					ia1 = 1;
				}
				if(common.tMask_rows < i){
					ia2 = common.tMask_rows;
				}
				else{
					ia2 = i;
				}

				s = 0.0f;

				for(ja = ja1; ja <= ja2; ja++){
					jb = jp1 - ja;
					for(ia = ia1; ia <= ia2; ia++){
						ib = ip1 - ia;
						s = s + d_tMask[tMask_base + common.tMask_rows * (ja - 1) + ia - 1] * 1.0f;
					}
				}

				d_mask_conv[mask_conv_base + (col - 1) * common.conv_rows + (row - 1)] =
					d_conv[conv_base + (col - 1) * common.conv_rows + (row - 1)] * s;
			}
		}

		fin_max_val = 0.0f;
		fin_max_coo = 0;
		for(i = 0; i < common.mask_conv_elem; i++){
			if(d_mask_conv[mask_conv_base + i] > fin_max_val){
				fin_max_val = d_mask_conv[mask_conv_base + i];
				fin_max_coo = i;
			}
		}

		largest_row = (fin_max_coo + 1) % common.mask_conv_rows - 1;
		largest_col = (fin_max_coo + 1) / common.mask_conv_rows;
		if((fin_max_coo + 1) % common.mask_conv_rows == 0){
			largest_row = common.mask_conv_rows - 1;
			largest_col = largest_col - 1;
		}

		largest_row = largest_row + 1;
		largest_col = largest_col + 1;
		offset_row = largest_row - common.in_rows - (common.sSize - common.tSize);
		offset_col = largest_col - common.in_cols - (common.sSize - common.tSize);
		pointer = point_no * common.no_frames + frame_no;
		d_tRowLoc[pointer] = d_Row[point_no] + offset_row;
		d_tColLoc[pointer] = d_Col[point_no] + offset_col;
	}

	if(frame_no != 0 && (frame_no % 10) == 0){

		loc_pointer = point_no * common.no_frames + frame_no;
		d_Row[point_no] = d_tRowLoc[loc_pointer];
		d_Col[point_no] = d_tColLoc[loc_pointer];

		for(col = 0; col < common.in_cols; col++){
			for(row = 0; row < common.in_rows; row++){

				ori_row = d_Row[point_no] - 25 + row - 1;
				ori_col = d_Col[point_no] - 25 + col - 1;
				ori_pointer = ori_col * common.frame_rows + ori_row;

				d_T[in_pointer + col * common.in_rows + row] =
					common.alpha * d_T[in_pointer + col * common.in_rows + row] +
					(1.00f - common.alpha) * d_frame[ori_pointer];
			}
		}
	}
}

#define fp float

typedef struct params_common{

	int common_change_mem;
	int common_mem;
	int unique_mem;

	int frames_processed;

	int sSize;
	int tSize;
	int maxMove;
	fp alpha;

	int no_frames;
	int frame_rows;
	int frame_cols;
	int frame_elem;
	int frame_mem;

	int endoPoints;
	int endo_mem;

	int epiPoints;
	int epi_mem;

	int allPoints;

	int in_rows;
	int in_cols;
	int in_elem;
	int in_mem;

	int in_pointer_mem;

	int in2_rows;
	int in2_cols;
	int in2_elem;
	int in2_mem;

	int conv_rows;
	int conv_cols;
	int conv_elem;
	int conv_mem;
	int ioffset;
	int joffset;

	int in2_pad_add_rows;
	int in2_pad_add_cols;
	int in2_pad_cumv_rows;
	int in2_pad_cumv_cols;
	int in2_pad_cumv_elem;
	int in2_pad_cumv_mem;

	int in2_pad_cumv_sel_rows;
	int in2_pad_cumv_sel_cols;
	int in2_pad_cumv_sel_elem;
	int in2_pad_cumv_sel_mem;
	int in2_pad_cumv_sel_rowlow;
	int in2_pad_cumv_sel_rowhig;
	int in2_pad_cumv_sel_collow;
	int in2_pad_cumv_sel_colhig;

	int in2_pad_cumv_sel2_rowlow;
	int in2_pad_cumv_sel2_rowhig;
	int in2_pad_cumv_sel2_collow;
	int in2_pad_cumv_sel2_colhig;
	int in2_sub_cumh_rows;
	int in2_sub_cumh_cols;
	int in2_sub_cumh_elem;
	int in2_sub_cumh_mem;

	int in2_sub_cumh_sel_rows;
	int in2_sub_cumh_sel_cols;
	int in2_sub_cumh_sel_elem;
	int in2_sub_cumh_sel_mem;
	int in2_sub_cumh_sel_rowlow;
	int in2_sub_cumh_sel_rowhig;
	int in2_sub_cumh_sel_collow;
	int in2_sub_cumh_sel_colhig;

	int in2_sub_cumh_sel2_rowlow;
	int in2_sub_cumh_sel2_rowhig;
	int in2_sub_cumh_sel2_collow;
	int in2_sub_cumh_sel2_colhig;
	int in2_sub2_rows;
	int in2_sub2_cols;
	int in2_sub2_elem;
	int in2_sub2_mem;

	int in2_sqr_rows;
	int in2_sqr_cols;
	int in2_sqr_elem;
	int in2_sqr_mem;

	int in2_sqr_sub2_rows;
	int in2_sqr_sub2_cols;
	int in2_sqr_sub2_elem;
	int in2_sqr_sub2_mem;

	int in_sqr_rows;
	int in_sqr_cols;
	int in_sqr_elem;
	int in_sqr_mem;

	int tMask_rows;
	int tMask_cols;
	int tMask_elem;
	int tMask_mem;

	int mask_rows;
	int mask_cols;
	int mask_elem;
	int mask_mem;

	int mask_conv_rows;
	int mask_conv_cols;
	int mask_conv_elem;
	int mask_conv_mem;
	int mask_conv_ioffset;
	int mask_conv_joffset;

} params_common;

typedef struct params_unique{
	int dummy;
} params_unique;

inline int idx2(int row, int col, int rows){
	return col * rows + row;
}

__kernel void kernel_gpu_opencl(
	__global const params_common* d_common,
	__global const params_unique* d_unique,
	__global const fp* d_frame,
	__global int* d_Row,
	__global int* d_Col,
	__global int* d_tRowLoc,
	__global int* d_tColLoc,
	__global fp* d_T,
	__global fp* d_in2,
	__global fp* d_conv,
	__global fp* d_in2_pad_cumv,
	__global fp* d_in2_sub_cumh,
	__global fp* d_in2_sub2,
	__global fp* d_in2_sqr,
	__global fp* d_in2_sqr_sub2,
	__global fp* d_in_sqr,
	__global fp* d_tMask,
	__global fp* d_mask_conv,
	int frame_no)
{
	(void)d_unique;

	params_common common = d_common[0];

	int point_id;
	if (get_num_groups(0) == (size_t)common.allPoints && get_local_size(0) > 1) {
		if (get_local_id(0) != 0) {
			return;
		}
		point_id = (int)get_group_id(0);
	} else {
		point_id = (int)get_global_id(0);
	}
	if (point_id >= common.allPoints) {
		return;
	}

	int in_pointer = point_id * common.in_elem;
	int in2_pointer = point_id * common.in2_elem;
	int conv_pointer = point_id * common.conv_elem;
	int in2_pad_cumv_pointer = point_id * common.in2_pad_cumv_elem;
	int in2_sub_cumh_pointer = point_id * common.in2_sub_cumh_elem;
	int in2_sub2_pointer = point_id * common.in2_sub2_elem;
	int in2_sqr_pointer = point_id * common.in2_sqr_elem;
	int in2_sqr_sub2_pointer = point_id * common.in2_sqr_sub2_elem;
	int in_sqr_pointer = point_id * common.in_sqr_elem;
	int tMask_pointer = point_id * common.tMask_elem;
	int mask_conv_pointer = point_id * common.mask_conv_elem;

	int ei_new;
	int rot_row;
	int rot_col;
	int in2_rowlow;
	int in2_collow;
	int ic;
	int jc;
	int jp1;
	int ja1, ja2;
	int ip1;
	int ia1, ia2;
	int ja, jb;
	int ia, ib;
	fp s;
	int i;
	int j;
	int row;
	int col;
	int ori_row;
	int ori_col;
	int position;
	fp sum;
	int pos_ori;
	fp temp;
	fp temp2;
	int cent;
	int tMask_row;
	int tMask_col;
	fp fin_max_val = 0.0f;
	int fin_max_coo = 0;
	int largest_row;
	int largest_col;
	int offset_row;
	int offset_col;
	fp in_final_sum;
	fp in_sqr_final_sum;
	fp mean;
	fp mean_sqr;
	fp variance;
	fp deviation;
	fp denomT;
	int pointer;
	int ori_pointer;
	int loc_pointer;

	__global fp* cur_in = d_T + in_pointer;
	__global fp* cur_in2 = d_in2 + in2_pointer;
	__global fp* cur_conv = d_conv + conv_pointer;
	__global fp* cur_in2_pad_cumv = d_in2_pad_cumv + in2_pad_cumv_pointer;
	__global fp* cur_in2_sub_cumh = d_in2_sub_cumh + in2_sub_cumh_pointer;
	__global fp* cur_in2_sub2 = d_in2_sub2 + in2_sub2_pointer;
	__global fp* cur_in2_sqr = d_in2_sqr + in2_sqr_pointer;
	__global fp* cur_in2_sqr_sub2 = d_in2_sqr_sub2 + in2_sqr_sub2_pointer;
	__global fp* cur_in_sqr = d_in_sqr + in_sqr_pointer;
	__global fp* cur_tMask = d_tMask + tMask_pointer;
	__global fp* cur_mask_conv = d_mask_conv + mask_conv_pointer;

	if (frame_no == 0) {
		pointer = point_id * common.no_frames + frame_no;
		d_tRowLoc[pointer] = d_Row[point_id];
		d_tColLoc[pointer] = d_Col[point_id];

		for (col = 0; col < common.in_cols; col++) {
			for (row = 0; row < common.in_rows; row++) {
				ori_row = d_Row[point_id] - 25 + row - 1;
				ori_col = d_Col[point_id] - 25 + col - 1;
				ori_pointer = ori_col * common.frame_rows + ori_row;
				cur_in[idx2(row, col, common.in_rows)] = d_frame[ori_pointer];
			}
		}
	}

	if (frame_no != 0) {

		in2_rowlow = d_Row[point_id] - common.sSize;
		in2_collow = d_Col[point_id] - common.sSize;

		for (col = 0; col < common.in2_cols; col++) {
			for (row = 0; row < common.in2_rows; row++) {
				ori_row = row + in2_rowlow - 1;
				ori_col = col + in2_collow - 1;
				temp = d_frame[ori_col * common.frame_rows + ori_row];
				cur_in2[idx2(row, col, common.in2_rows)] = temp;
				cur_in2_sqr[idx2(row, col, common.in2_rows)] = temp * temp;
			}
		}

		for (col = 0; col < common.in_cols; col++) {
			for (row = 0; row < common.in_rows; row++) {
				rot_row = (common.in_rows - 1) - row;
				rot_col = (common.in_rows - 1) - col;
				pointer = idx2(rot_row, rot_col, common.in_rows);
				temp = cur_in[pointer];
				cur_in[idx2(row, col, common.in_rows)] = cur_in[idx2(row, col, common.in_rows)];
				cur_in_sqr[pointer] = temp * temp;
				cur_in[idx2(row, col, common.in_rows)] = cur_in[idx2(row, col, common.in_rows)];
				cur_in_sqr[idx2(rot_row, rot_col, common.in_rows)] = temp * temp;
			}
		}

		for (col = 0; col < common.in_cols; col++) {
			for (row = 0; row < common.in_rows; row++) {
				rot_row = (common.in_rows - 1) - row;
				rot_col = (common.in_rows - 1) - col;
				pointer = idx2(rot_row, rot_col, common.in_rows);
				temp = cur_in[pointer];
				cur_in_sqr[pointer] = temp * temp;
				cur_in[idx2(row, col, common.in_rows)] = cur_in[idx2(row, col, common.in_rows)];
			}
		}

		in_final_sum = 0.0f;
		for (i = 0; i < common.in_elem; i++) {
			in_final_sum = in_final_sum + cur_in[i];
		}

		in_sqr_final_sum = 0.0f;
		for (i = 0; i < common.in_elem; i++) {
			in_sqr_final_sum = in_sqr_final_sum + cur_in_sqr[i];
		}

		mean = in_final_sum / (fp)common.in_elem;
		mean_sqr = mean * mean;
		variance = (in_sqr_final_sum / (fp)common.in_elem) - mean_sqr;
		deviation = sqrt(variance);
		denomT = sqrt((fp)(common.in_elem - 1)) * deviation;

		for (col = 1; col <= common.conv_cols; col++) {
			j = col + common.joffset;
			jp1 = j + 1;
			if (common.in2_cols < jp1) {
				ja1 = jp1 - common.in2_cols;
			} else {
				ja1 = 1;
			}
			if (common.in_cols < j) {
				ja2 = common.in_cols;
			} else {
				ja2 = j;
			}

			for (row = 1; row <= common.conv_rows; row++) {
				i = row + common.ioffset;
				ip1 = i + 1;

				if (common.in2_rows < ip1) {
					ia1 = ip1 - common.in2_rows;
				} else {
					ia1 = 1;
				}
				if (common.in_rows < i) {
					ia2 = common.in_rows;
				} else {
					ia2 = i;
				}

				s = 0.0f;

				for (ja = ja1; ja <= ja2; ja++) {
					jb = jp1 - ja;
					for (ia = ia1; ia <= ia2; ia++) {
						ib = ip1 - ia;
						s = s +
							cur_in[idx2(ia - 1, ja - 1, common.in_rows)] *
							cur_in2[idx2(ib - 1, jb - 1, common.in2_rows)];
					}
				}

				cur_conv[idx2(row - 1, col - 1, common.conv_rows)] = s;
			}
		}

		for (col = 0; col < common.in2_pad_cumv_cols; col++) {
			for (row = 0; row < common.in2_pad_cumv_rows; row++) {
				if (row > (common.in2_pad_add_rows - 1) &&
					row < (common.in2_pad_add_rows + common.in2_rows) &&
					col > (common.in2_pad_add_cols - 1) &&
					col < (common.in2_pad_add_cols + common.in2_cols)) {
					ori_row = row - common.in2_pad_add_rows;
					ori_col = col - common.in2_pad_add_cols;
					cur_in2_pad_cumv[idx2(row, col, common.in2_pad_cumv_rows)] =
						cur_in2[idx2(ori_row, ori_col, common.in2_rows)];
				} else {
					cur_in2_pad_cumv[idx2(row, col, common.in2_pad_cumv_rows)] = 0.0f;
				}
			}
		}

		for (ei_new = 0; ei_new < common.in2_pad_cumv_cols; ei_new++) {
			pos_ori = ei_new * common.in2_pad_cumv_rows;
			sum = 0.0f;
			for (position = pos_ori; position < pos_ori + common.in2_pad_cumv_rows; position++) {
				cur_in2_pad_cumv[position] = cur_in2_pad_cumv[position] + sum;
				sum = cur_in2_pad_cumv[position];
			}
		}

		for (col = 0; col < common.in2_sub_cumh_cols; col++) {
			for (row = 0; row < common.in2_sub_cumh_rows; row++) {
				ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
				ori_col = col + common.in2_pad_cumv_sel_collow - 1;
				temp = cur_in2_pad_cumv[idx2(ori_row, ori_col, common.in2_pad_cumv_rows)];

				ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
				ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
				temp2 = cur_in2_pad_cumv[idx2(ori_row, ori_col, common.in2_pad_cumv_rows)];

				cur_in2_sub_cumh[idx2(row, col, common.in2_sub_cumh_rows)] = temp - temp2;
			}
		}

		for (ei_new = 0; ei_new < common.in2_sub_cumh_rows; ei_new++) {
			pos_ori = ei_new;
			sum = 0.0f;
			for (position = pos_ori; position < pos_ori + common.in2_sub_cumh_elem; position += common.in2_sub_cumh_rows) {
				cur_in2_sub_cumh[position] = cur_in2_sub_cumh[position] + sum;
				sum = cur_in2_sub_cumh[position];
			}
		}

		for (col = 0; col < common.in2_sub2_cols; col++) {
			for (row = 0; row < common.in2_sub2_rows; row++) {
				ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel_collow - 1;
				temp = cur_in2_sub_cumh[idx2(ori_row, ori_col, common.in2_sub_cumh_rows)];

				ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
				temp2 = cur_in2_sub_cumh[idx2(ori_row, ori_col, common.in2_sub_cumh_rows)];

				temp2 = temp - temp2;

				cur_in2_sub2[idx2(row, col, common.in2_sub2_rows)] = temp2 * temp2;
				cur_conv[idx2(row, col, common.conv_rows)] =
					cur_conv[idx2(row, col, common.conv_rows)] -
					temp2 * in_final_sum / (fp)common.in_elem;
			}
		}

		for (col = 0; col < common.in2_pad_cumv_cols; col++) {
			for (row = 0; row < common.in2_pad_cumv_rows; row++) {
				if (row > (common.in2_pad_add_rows - 1) &&
					row < (common.in2_pad_add_rows + common.in2_rows) &&
					col > (common.in2_pad_add_cols - 1) &&
					col < (common.in2_pad_add_cols + common.in2_cols)) {
					ori_row = row - common.in2_pad_add_rows;
					ori_col = col - common.in2_pad_add_cols;
					cur_in2_pad_cumv[idx2(row, col, common.in2_pad_cumv_rows)] =
						cur_in2_sqr[idx2(ori_row, ori_col, common.in2_rows)];
				} else {
					cur_in2_pad_cumv[idx2(row, col, common.in2_pad_cumv_rows)] = 0.0f;
				}
			}
		}

		for (ei_new = 0; ei_new < common.in2_pad_cumv_cols; ei_new++) {
			pos_ori = ei_new * common.in2_pad_cumv_rows;
			sum = 0.0f;
			for (position = pos_ori; position < pos_ori + common.in2_pad_cumv_rows; position++) {
				cur_in2_pad_cumv[position] = cur_in2_pad_cumv[position] + sum;
				sum = cur_in2_pad_cumv[position];
			}
		}

		for (col = 0; col < common.in2_sub_cumh_cols; col++) {
			for (row = 0; row < common.in2_sub_cumh_rows; row++) {
				ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
				ori_col = col + common.in2_pad_cumv_sel_collow - 1;
				temp = cur_in2_pad_cumv[idx2(ori_row, ori_col, common.in2_pad_cumv_rows)];

				ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
				ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
				temp2 = cur_in2_pad_cumv[idx2(ori_row, ori_col, common.in2_pad_cumv_rows)];

				cur_in2_sub_cumh[idx2(row, col, common.in2_sub_cumh_rows)] = temp - temp2;
			}
		}

		for (ei_new = 0; ei_new < common.in2_sub_cumh_rows; ei_new++) {
			pos_ori = ei_new;
			sum = 0.0f;
			for (position = pos_ori; position < pos_ori + common.in2_sub_cumh_elem; position += common.in2_sub_cumh_rows) {
				cur_in2_sub_cumh[position] = cur_in2_sub_cumh[position] + sum;
				sum = cur_in2_sub_cumh[position];
			}
		}

		for (col = 0; col < common.conv_cols; col++) {
			for (row = 0; row < common.conv_rows; row++) {
				ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel_collow - 1;
				temp = cur_in2_sub_cumh[idx2(ori_row, ori_col, common.in2_sub_cumh_rows)];

				ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
				temp2 = cur_in2_sub_cumh[idx2(ori_row, ori_col, common.in2_sub_cumh_rows)];

				temp2 = temp - temp2;

				cur_in2_sqr_sub2[idx2(row, col, common.conv_rows)] = temp2;

				temp2 = temp2 - (cur_in2_sub2[idx2(row, col, common.conv_rows)] / (fp)common.in_elem);

				if (temp2 < 0.0f) {
					temp2 = 0.0f;
				}
				temp2 = sqrt(temp2);

				temp2 = denomT * temp2;

				cur_conv[idx2(row, col, common.conv_rows)] =
					cur_conv[idx2(row, col, common.conv_rows)] / temp2;
			}
		}

		cent = common.sSize + common.tSize + 1;
		pointer = frame_no - 1 + point_id * common.no_frames;
		tMask_row = cent + d_tRowLoc[pointer] - d_Row[point_id] - 1;
		tMask_col = cent + d_tColLoc[pointer] - d_Col[point_id] - 1;

		for (ei_new = 0; ei_new < common.tMask_elem; ei_new++) {
			cur_tMask[ei_new] = 0.0f;
		}
		cur_tMask[idx2(tMask_row, tMask_col, common.tMask_rows)] = 1.0f;

		for (col = 1; col <= common.mask_conv_cols; col++) {
			j = col + common.mask_conv_joffset;
			jp1 = j + 1;
			if (common.mask_cols < jp1) {
				ja1 = jp1 - common.mask_cols;
			} else {
				ja1 = 1;
			}
			if (common.tMask_cols < j) {
				ja2 = common.tMask_cols;
			} else {
				ja2 = j;
			}

			for (row = 1; row <= common.mask_conv_rows; row++) {
				i = row + common.mask_conv_ioffset;
				ip1 = i + 1;

				if (common.mask_rows < ip1) {
					ia1 = ip1 - common.mask_rows;
				} else {
					ia1 = 1;
				}
				if (common.tMask_rows < i) {
					ia2 = common.tMask_rows;
				} else {
					ia2 = i;
				}

				s = 0.0f;

				for (ja = ja1; ja <= ja2; ja++) {
					jb = jp1 - ja;
					(void)jb;
					for (ia = ia1; ia <= ia2; ia++) {
						ib = ip1 - ia;
						(void)ib;
						s = s + cur_tMask[idx2(ia - 1, ja - 1, common.tMask_rows)] * 1.0f;
					}
				}

				cur_mask_conv[idx2(row - 1, col - 1, common.conv_rows)] =
					cur_conv[idx2(row - 1, col - 1, common.conv_rows)] * s;
			}
		}

		fin_max_val = 0.0f;
		fin_max_coo = 0;
		for (i = 0; i < common.mask_conv_elem; i++) {
			if (cur_mask_conv[i] > fin_max_val) {
				fin_max_val = cur_mask_conv[i];
				fin_max_coo = i;
			}
		}

		largest_row = (fin_max_coo + 1) % common.mask_conv_rows - 1;
		largest_col = (fin_max_coo + 1) / common.mask_conv_rows;
		if ((fin_max_coo + 1) % common.mask_conv_rows == 0) {
			largest_row = common.mask_conv_rows - 1;
			largest_col = largest_col - 1;
		}

		largest_row = largest_row + 1;
		largest_col = largest_col + 1;
		offset_row = largest_row - common.in_rows - (common.sSize - common.tSize);
		offset_col = largest_col - common.in_cols - (common.sSize - common.tSize);
		pointer = point_id * common.no_frames + frame_no;
		d_tRowLoc[pointer] = d_Row[point_id] + offset_row;
		d_tColLoc[pointer] = d_Col[point_id] + offset_col;
	}

	if (frame_no != 0 && (frame_no % 10) == 0) {
		loc_pointer = point_id * common.no_frames + frame_no;
		d_Row[point_id] = d_tRowLoc[loc_pointer];
		d_Col[point_id] = d_tColLoc[loc_pointer];

		for (col = 0; col < common.in_cols; col++) {
			for (row = 0; row < common.in_rows; row++) {
				ori_row = d_Row[point_id] - 25 + row - 1;
				ori_col = d_Col[point_id] - 25 + col - 1;
				ori_pointer = ori_col * common.frame_rows + ori_row;

				cur_in[idx2(row, col, common.in_rows)] =
					common.alpha * cur_in[idx2(row, col, common.in_rows)] +
					(1.00f - common.alpha) * d_frame[ori_pointer];
			}
		}
	}
}

#define fp float

typedef struct params_common{

	int common_change_mem;
	int common_mem;
	int unique_mem;

	int frames_processed;

	int sSize;
	int tSize;
	int maxMove;
	fp alpha;

	int no_frames;
	int frame_rows;
	int frame_cols;
	int frame_elem;
	int frame_mem;

	int endoPoints;
	int endo_mem;

	int epiPoints;
	int epi_mem;

	int allPoints;

	int in_rows;
	int in_cols;
	int in_elem;
	int in_mem;

	int in_pointer_mem;

	int in2_rows;
	int in2_cols;
	int in2_elem;
	int in2_mem;

	int conv_rows;
	int conv_cols;
	int conv_elem;
	int conv_mem;
	int ioffset;
	int joffset;

	int in2_pad_add_rows;
	int in2_pad_add_cols;
	int in2_pad_cumv_rows;
	int in2_pad_cumv_cols;
	int in2_pad_cumv_elem;
