	int in2_pad_cumv_sel_rowhig;
	int in2_pad_cumv_sel_collow;
	int in2_pad_cumv_sel_colhig;

	int in2_pad_cumv_sel2_rowlow;
	int in2_pad_cumv_sel2_rowhig;
	int in2_pad_cumv_sel2_collow;
	int in2_pad_cumv_sel2_colhig;
	int in2_sub_cumh_rows;
	int in2_sub_cumh_cols;
	int in2_sub_cumh_elem;
	int in2_sub_cumh_mem;

	int in2_sub_cumh_sel_rows;
	int in2_sub_cumh_sel_cols;
	int in2_sub_cumh_sel_elem;
	int in2_sub_cumh_sel_mem;
	int in2_sub_cumh_sel_rowlow;
	int in2_sub_cumh_sel_rowhig;
	int in2_sub_cumh_sel_collow;
	int in2_sub_cumh_sel_colhig;

	int in2_sub_cumh_sel2_rowlow;
	int in2_sub_cumh_sel2_rowhig;
	int in2_sub_cumh_sel2_collow;
	int in2_sub_cumh_sel2_colhig;
	int in2_sub2_rows;
	int in2_sub2_cols;
	int in2_sub2_elem;
	int in2_sub2_mem;

	int in2_sqr_rows;
	int in2_sqr_cols;
	int in2_sqr_elem;
	int in2_sqr_mem;

	int in2_sqr_sub2_rows;
	int in2_sqr_sub2_cols;
	int in2_sqr_sub2_elem;
	int in2_sqr_sub2_mem;

	int in_sqr_rows;
	int in_sqr_cols;
	int in_sqr_elem;
	int in_sqr_mem;

	int tMask_rows;
	int tMask_cols;
	int tMask_elem;
	int tMask_mem;

	int mask_rows;
	int mask_cols;
	int mask_elem;
	int mask_mem;

	int mask_conv_rows;
	int mask_conv_cols;
	int mask_conv_elem;
	int mask_conv_mem;
	int mask_conv_ioffset;
	int mask_conv_joffset;

} params_common;

inline void heartwall_core(
	params_common common,
	int frame_no,
	int point_no,
	__global int* d_Row,
	__global int* d_Col,
	__global int* d_tRowLoc,
	__global int* d_tColLoc,
	__global fp* d_T,
	__global fp* d_frame,
	__global uchar* d_unique)
{
	int col, row, i, j;
	int ori_row, ori_col, ori_pointer;
	int pointer, loc_pointer;
	int in2_rowlow, in2_collow;
	int rot_row, rot_col;
	int jp1, ip1, ja1, ja2, ia1, ia2, ja, jb, ia, ib;
	int position, pos_ori, ei_new;
	int cent, tMask_row, tMask_col;
	int largest_row, largest_col, offset_row, offset_col;

	fp temp, temp2, sum, s;
	fp in_final_sum, in_sqr_final_sum;
	fp mean, mean_sqr, variance, deviation, denomT;
	fp fin_max_val;

	__global fp* base = (__global fp*)(d_unique + ((size_t)point_no * (size_t)common.unique_mem));

	int off_in2 = 0;
	int off_in2_sqr = off_in2 + common.in2_elem;
	int off_conv = off_in2_sqr + common.in2_elem;
	int off_in2_pad = off_conv + common.conv_elem;
	int off_in2_sub = off_in2_pad + common.in2_pad_cumv_elem;
	int off_in2_sub2_sqr = off_in2_sub + common.in2_sub_cumh_elem;
	int off_tMask = off_in2_sub2_sqr + common.in2_sub2_elem;
	int off_mask_conv = off_tMask + common.tMask_elem;

	__global fp* d_in2 = base + off_in2;
	__global fp* d_in2_sqr = base + off_in2_sqr;
	__global fp* d_conv = base + off_conv;
	__global fp* d_in2_pad = base + off_in2_pad;
	__global fp* d_in2_sub = base + off_in2_sub;
	__global fp* d_in2_sub2_sqr = base + off_in2_sub2_sqr;
	__global fp* d_tMask = base + off_tMask;
	__global fp* d_mask_conv = base + off_mask_conv;

	__global fp* d_in = &d_T[point_no * common.in_elem];

	if(frame_no == 0){
		pointer = point_no * common.no_frames + frame_no;
		d_tRowLoc[pointer] = d_Row[point_no];
		d_tColLoc[pointer] = d_Col[point_no];

		for(col = 0; col < common.in_cols; col++){
			for(row = 0; row < common.in_rows; row++){
				ori_row = d_Row[point_no] - common.tSize + row - 1;
				ori_col = d_Col[point_no] - common.tSize + col - 1;
				ori_pointer = ori_col * common.frame_rows + ori_row;
				d_in[col * common.in_rows + row] = d_frame[ori_pointer];
			}
		}
	}

	if(frame_no != 0){

		in2_rowlow = d_Row[point_no] - common.sSize;
		in2_collow = d_Col[point_no] - common.sSize;

		for(col = 0; col < common.in2_cols; col++){
			for(row = 0; row < common.in2_rows; row++){
				ori_row = row + in2_rowlow - 1;
				ori_col = col + in2_collow - 1;
				temp = d_frame[ori_col * common.frame_rows + ori_row];
				d_in2[col * common.in2_rows + row] = temp;
				d_in2_sqr[col * common.in2_rows + row] = temp * temp;
			}
		}

		in_final_sum = 0.0f;
		in_sqr_final_sum = 0.0f;
		for(i = 0; i < common.in_elem; i++){
			temp = d_in[i];
			in_final_sum += temp;
			in_sqr_final_sum += temp * temp;
		}

		mean = in_final_sum / (fp)common.in_elem;
		mean_sqr = mean * mean;
		variance = (in_sqr_final_sum / (fp)common.in_elem) - mean_sqr;
		deviation = sqrt(variance);
		denomT = sqrt((fp)(common.in_elem - 1)) * deviation;

		for(col = 1; col <= common.conv_cols; col++){
			j = col + common.joffset;
			jp1 = j + 1;

			if(common.in2_cols < jp1){
				ja1 = jp1 - common.in2_cols;
			}
			else{
				ja1 = 1;
			}

			if(common.in_cols < j){
				ja2 = common.in_cols;
			}
			else{
				ja2 = j;
			}

			for(row = 1; row <= common.conv_rows; row++){
				i = row + common.ioffset;
				ip1 = i + 1;

				if(common.in2_rows < ip1){
					ia1 = ip1 - common.in2_rows;
				}
				else{
					ia1 = 1;
				}

				if(common.in_rows < i){
					ia2 = common.in_rows;
				}
				else{
					ia2 = i;
				}

				s = 0.0f;

				for(ja = ja1; ja <= ja2; ja++){
					jb = jp1 - ja;
					for(ia = ia1; ia <= ia2; ia++){
						ib = ip1 - ia;
						s += d_in[(common.in_rows - ja) * common.in_rows + (common.in_rows - ia)] *
							 d_in2[common.in2_rows * (jb - 1) + (ib - 1)];
					}
				}

				d_conv[(col - 1) * common.conv_rows + (row - 1)] = s;
			}
		}

		for(col = 0; col < common.in2_pad_cumv_cols; col++){
			for(row = 0; row < common.in2_pad_cumv_rows; row++){
				if(	row > (common.in2_pad_add_rows - 1) &&
					row < (common.in2_pad_add_rows + common.in2_rows) &&
					col > (common.in2_pad_add_cols - 1) &&
					col < (common.in2_pad_add_cols + common.in2_cols)){
					ori_row = row - common.in2_pad_add_rows;
					ori_col = col - common.in2_pad_add_cols;
					d_in2_pad[col * common.in2_pad_cumv_rows + row] = d_in2[ori_col * common.in2_rows + ori_row];
				}
				else{
					d_in2_pad[col * common.in2_pad_cumv_rows + row] = 0.0f;
				}
			}
		}

		for(ei_new = 0; ei_new < common.in2_pad_cumv_cols; ei_new++){
			pos_ori = ei_new * common.in2_pad_cumv_rows;
			sum = 0.0f;
			for(position = pos_ori; position < pos_ori + common.in2_pad_cumv_rows; position++){
				d_in2_pad[position] = d_in2_pad[position] + sum;
				sum = d_in2_pad[position];
			}
		}

		for(col = 0; col < common.in2_sub_cumh_cols; col++){
			for(row = 0; row < common.in2_sub_cumh_rows; row++){
				ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
				ori_col = col + common.in2_pad_cumv_sel_collow - 1;
				temp = d_in2_pad[ori_col * common.in2_pad_cumv_rows + ori_row];

				ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
				ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
				temp2 = d_in2_pad[ori_col * common.in2_pad_cumv_rows + ori_row];

				d_in2_sub[col * common.in2_sub_cumh_rows + row] = temp - temp2;
			}
		}

		for(ei_new = 0; ei_new < common.in2_sub_cumh_rows; ei_new++){
			pos_ori = ei_new;
			sum = 0.0f;
			for(position = pos_ori; position < pos_ori + common.in2_sub_cumh_elem; position += common.in2_sub_cumh_rows){
				d_in2_sub[position] = d_in2_sub[position] + sum;
				sum = d_in2_sub[position];
			}
		}

		for(col = 0; col < common.in2_sub2_cols; col++){
			for(row = 0; row < common.in2_sub2_rows; row++){
				ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel_collow - 1;
				temp = d_in2_sub[ori_col * common.in2_sub_cumh_rows + ori_row];

				ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
				temp2 = d_in2_sub[ori_col * common.in2_sub_cumh_rows + ori_row];

				temp2 = temp - temp2;
				d_in2_sub2_sqr[col * common.in2_sub2_rows + row] = temp2 * temp2;
				d_conv[col * common.in2_sub2_rows + row] =
					d_conv[col * common.in2_sub2_rows + row] - temp2 * in_final_sum / (fp)common.in_elem;
			}
		}

		for(col = 0; col < common.in2_pad_cumv_cols; col++){
			for(row = 0; row < common.in2_pad_cumv_rows; row++){
				if(	row > (common.in2_pad_add_rows - 1) &&
					row < (common.in2_pad_add_rows + common.in2_rows) &&
					col > (common.in2_pad_add_cols - 1) &&
					col < (common.in2_pad_add_cols + common.in2_cols)){
					ori_row = row - common.in2_pad_add_rows;
					ori_col = col - common.in2_pad_add_cols;
					d_in2_pad[col * common.in2_pad_cumv_rows + row] = d_in2_sqr[ori_col * common.in2_rows + ori_row];
				}
				else{
					d_in2_pad[col * common.in2_pad_cumv_rows + row] = 0.0f;
				}
			}
		}

