    const int ty = (int)get_local_id(1);
    const int bx = (int)get_group_id(0);
    const int by = (int)get_group_id(1);

    const int small_block_cols = BLOCK_SIZE - (borderCols << 1);
    const int small_block_rows = BLOCK_SIZE - (borderRows << 1);

    const int x = bx * small_block_cols + tx - borderCols;
    const int y = by * small_block_rows + ty - borderRows;
    const int lidx = ty * BLOCK_SIZE + tx;

    __local float local_a[BLOCK_SIZE * BLOCK_SIZE];
    __local float local_b[BLOCK_SIZE * BLOCK_SIZE];

    __local float *src = local_a;
    __local float *dst = local_b;

