__kernel void hotspotOpt1(__global const float *pIn,
                          __global float *tIn,
                          __global float *tOut,
                          const float stepDivCap,
                          const int nx,
                          const int ny,
                          const int nz,
                          const float ce,
                          const float cw,
                          const float cn,
                          const float cs,
                          const float ct,
                          const float cb,
                          const float cc)
{
    if (get_global_id(0) != 0 || get_global_id(1) != 0)
        return;

    const float amb_temp = 80.0f;
    const int plane = nx * ny;

    for (int z = 0; z < nz; z++) {
        for (int y = 0; y < ny; y++) {
            for (int x = 0; x < nx; x++) {
                int c = x + y * nx + z * plane;

                int w = (x == 0)      ? c : c - 1;
                int e = (x == nx - 1) ? c : c + 1;
                int n = (y == 0)      ? c : c - nx;
                int s = (y == ny - 1) ? c : c + nx;
                int b = (z == 0)      ? c : c - plane;
                int t = (z == nz - 1) ? c : c + plane;

                tOut[c] = cc * tIn[c]
                        + cw * tIn[w]
                        + ce * tIn[e]
                        + cn * tIn[n]
                        + cs * tIn[s]
                        + cb * tIn[b]
                        + ct * tIn[t]
                        + stepDivCap * pIn[c]
                        + ct * amb_temp;
            }
        }
    }

    for (int i = 0; i < plane * nz; i++) {
        tIn[i] = tOut[i];
