__kernel void hotspotOpt1(__global const float *pIn,
                          __global float *tIn,
                          __global float *tOut,
                          const float stepDivCap,
                          const int nx,
                          const int ny,
                          const int nz,
                          const float ce,
                          const float cw,
                          const float cn,
                          const float cs,
                          const float ct,
                          const float cb,
                          const float cc)
{
    if (get_global_id(0) != 0 || get_global_id(1) != 0)
