                int w = (x == 0)      ? c : c - 1;
                int e = (x == nx - 1) ? c : c + 1;
                int n = (y == 0)      ? c : c - nx;
                int s = (y == ny - 1) ? c : c + nx;
                int b = (z == 0)      ? c : c - nx * ny;
                int t = (z == nz - 1) ? c : c + nx * ny;

                tOut[c] = tIn[c] * cc +
                          tIn[n] * cn +
                          tIn[s] * cs +
                          tIn[e] * ce +
                          tIn[w] * cw +
                          tIn[t] * ct +
                          tIn[b] * cb +
                          stepDivCap * pIn[c] +
                          ct * amb;
