        const int c = hotspot_index(x, y, z, nx, ny);

        const int w = (x == 0)      ? c : c - 1;
        const int e = (x == nx - 1) ? c : c + 1;
        const int n = (y == 0)      ? c : c - nx;
        const int s = (y == ny - 1) ? c : c + nx;
        const int b = (z == 0)      ? c : c - nx * ny;
        const int t = (z == nz - 1) ? c : c + nx * ny;

