    I_pca_sl = Fsl *
               pow(Q10SLCaP,Qpow) *
               IbarSLCaP *
               pow(initvalu_37,1.6f) /
               (pow(KmPCa,1.6f) + pow(initvalu_37,1.6f));
    I_pca = I_pca_junc+I_pca_sl;
    finavalu[offset_44]=-I_pca*Cmem/(Vmyo*2.0f*Frdy)*1e3f;

    I_cabk_junc = Fjunc*GCaB*(initvalu_39-eca_junc);
    I_cabk_sl = Fsl*GCaB*(initvalu_39-eca_sl);
    I_cabk = I_cabk_junc+I_cabk_sl;
    finavalu[offset_46]=-I_cabk*Cmem/(Vmyo*2.0f*Frdy)*1e3f;

    MaxSR = 15.0f;
    MinSR = 1.0f;
    kCaSR = MaxSR - (MaxSR-MinSR)/(1.0f+pow(ec50SR/initvalu_31,2.5f));
    koSRCa = koCa/kCaSR;
    kiSRCa = kiCa*kCaSR;
    RI = 1.0f-initvalu_14-initvalu_15-initvalu_16;
    finavalu[offset_14] = (kim*RI-kiSRCa*initvalu_36*initvalu_14)-(koSRCa*pow(initvalu_36,2.0f)*initvalu_14-kom*initvalu_15);
    finavalu[offset_15] = (koSRCa*pow(initvalu_36,2.0f)*initvalu_14-kom*initvalu_15)-(kiSRCa*initvalu_36*initvalu_15-kim*initvalu_16);
    finavalu[offset_16] = (kiSRCa*initvalu_36*initvalu_15-kim*initvalu_16)-(kom*initvalu_16-koSRCa*pow(initvalu_36,2.0f)*RI);
    J_SRCarel = ks*initvalu_15*(initvalu_31-initvalu_36);
    J_serca = pow(Q10SRCaP,Qpow)*Vmax_SRCaP*(pow((initvalu_38/Kmf),hillSRCaP)-pow((initvalu_31/Kmr),hillSRCaP))
             /(1.0f+pow((initvalu_38/Kmf),hillSRCaP)+pow((initvalu_31/Kmr),hillSRCaP));
    J_SRleak = 5.348e-6f*(initvalu_31-initvalu_36);

    finavalu[offset_17] = kon_na*initvalu_32*(Bmax_Naj-initvalu_17)-koff_na*initvalu_17;
    finavalu[offset_18] = kon_na*initvalu_33*(Bmax_Nasl-initvalu_18)-koff_na*initvalu_18;

    finavalu[offset_19] = kon_tncl*initvalu_38*(Bmax_TnClow-initvalu_19)-koff_tncl*initvalu_19;
    finavalu[offset_20] = kon_tnchca*initvalu_38*(Bmax_TnChigh-initvalu_20-initvalu_21)-koff_tnchca*initvalu_20;
    finavalu[offset_21] = kon_tnchmg*Mgi*(Bmax_TnChigh-initvalu_20-initvalu_21)-koff_tnchmg*initvalu_21;
    finavalu[offset_22] = 0.0f;
    finavalu[offset_23] = kon_myoca*initvalu_38*(Bmax_myosin-initvalu_23-initvalu_24)-koff_myoca*initvalu_23;
    finavalu[offset_24] = kon_myomg*Mgi*(Bmax_myosin-initvalu_23-initvalu_24)-koff_myomg*initvalu_24;
    finavalu[offset_25] = kon_sr*initvalu_38*(Bmax_SR-initvalu_25)-koff_sr*initvalu_25;
    J_CaB_cytosol = finavalu[offset_19] + finavalu[offset_20] + finavalu[offset_21] + finavalu[offset_22] + finavalu[offset_23] + finavalu[offset_24] + finavalu[offset_25];

    finavalu[offset_26] = kon_sll*initvalu_36*(Bmax_SLlowj-initvalu_26)-koff_sll*initvalu_26;
    finavalu[offset_27] = kon_sll*initvalu_37*(Bmax_SLlowsl-initvalu_27)-koff_sll*initvalu_27;
    finavalu[offset_28] = kon_slh*initvalu_36*(Bmax_SLhighj-initvalu_28)-koff_slh*initvalu_28;
    finavalu[offset_29] = kon_slh*initvalu_37*(Bmax_SLhighsl-initvalu_29)-koff_slh*initvalu_29;
    J_CaB_junction = finavalu[offset_26]+finavalu[offset_28];
    J_CaB_sl = finavalu[offset_27]+finavalu[offset_29];

    finavalu[offset_30] = kon_csqn*initvalu_31*(Bmax_Csqn-initvalu_30)-koff_csqn*initvalu_30;
    oneovervsr = 1.0f/Vsr;
    finavalu[offset_31] = J_serca*Vmyo*oneovervsr-(J_SRleak*Vmyo*oneovervsr+J_SRCarel)-finavalu[offset_30];

    I_Na_tot_junc = I_Na_junc+I_nabk_junc+3.0f*I_ncx_junc+3.0f*I_nak_junc+I_CaNa_junc;
    I_Na_tot_sl = I_Na_sl+I_nabk_sl+3.0f*I_ncx_sl+3.0f*I_nak_sl+I_CaNa_sl;
    finavalu[offset_32] = -I_Na_tot_junc*Cmem/(Vjunc*Frdy)+J_na_juncsl/Vjunc*(initvalu_33-initvalu_32)-finavalu[offset_17];
    oneovervsl = 1.0f/Vsl;
    finavalu[offset_33] = -I_Na_tot_sl*Cmem*oneovervsl/Frdy+J_na_juncsl*oneovervsl*(initvalu_32-initvalu_33)+J_na_slmyo*oneovervsl*(initvalu_34-initvalu_33)-finavalu[offset_18];
    finavalu[offset_34] = J_na_slmyo/Vmyo*(initvalu_33-initvalu_34);

    I_K_tot = I_to+I_kr+I_ks+I_ki-2.0f*I_nak+I_CaK+I_kp;
    finavalu[offset_35] = 0.0f;

    I_Ca_tot_junc = I_Ca_junc+I_cabk_junc+I_pca_junc-2.0f*I_ncx_junc;
    I_Ca_tot_sl = I_Ca_sl+I_cabk_sl+I_pca_sl-2.0f*I_ncx_sl;
    finavalu[offset_36] = -I_Ca_tot_junc*Cmem/(Vjunc*2.0f*Frdy)+J_ca_juncsl/Vjunc*(initvalu_37-initvalu_36)
             - J_CaB_junction+(J_SRCarel)*Vsr/Vjunc+J_SRleak*Vmyo/Vjunc;
    finavalu[offset_37] = -I_Ca_tot_sl*Cmem/(Vsl*2.0f*Frdy)+J_ca_juncsl/Vsl*(initvalu_36-initvalu_37)
             + J_ca_slmyo/Vsl*(initvalu_38-initvalu_37)-J_CaB_sl;
    finavalu[offset_38] = -J_serca-J_CaB_cytosol +J_ca_slmyo/Vmyo*(initvalu_37-initvalu_38);
    junc_sl=J_ca_juncsl/Vsl*(initvalu_36-initvalu_37);
    sl_junc=J_ca_juncsl/Vjunc*(initvalu_37-initvalu_36);
    sl_myo=J_ca_slmyo/Vsl*(initvalu_38-initvalu_37);
    myo_sl=J_ca_slmyo/Vmyo*(initvalu_37-initvalu_38);

    state = 1;
    switch(state){
        case 0:
            I_app = 0.0f;
            break;
        case 1:
            if(fmod(timeinst,parameter_1) <= 5.0f){
                I_app = 9.5f;
            }
            else{
                I_app = 0.0f;
            }
            break;
        case 2:
            V_hold = -55.0f;
            V_test = 0.0f;
            if((timeinst>0.5f) && (timeinst<200.5f)){
                V_clamp = V_test;
            }
            else{
                V_clamp = V_hold;
            }
            R_clamp = 0.04f;
            I_app = (V_clamp-initvalu_39)/R_clamp;
            break;
        default:
            I_app = 0.0f;
            break;
    }

    I_Na_tot = I_Na_tot_junc + I_Na_tot_sl;
    I_Cl_tot = I_ClCa+I_Clbk;
    I_Ca_tot = I_Ca_tot_junc+I_Ca_tot_sl;
    I_tot = I_Na_tot+I_Cl_tot+I_Ca_tot+I_K_tot;
    finavalu[offset_39] = -(I_tot-I_app);

    finavalu[offset_41] = 0.0f;
    finavalu[offset_42] = 0.0f;
}

__kernel void kernel_gpu_opencl(fp timeinst,
                                __global const fp *initvalu,
                                __global fp *finavalu,
                                __global const fp *parameter,
                                __global fp *com)
{
    if (get_global_id(0) != 0)
        return;

    kernel_ecc(timeinst, initvalu, 0, parameter, 0, finavalu);

    com[0] = kernel_cam(timeinst, initvalu, 46, parameter, 1, finavalu, initvalu[35]*1e3f);
    com[1] = kernel_cam(timeinst, initvalu, 61, parameter, 6, finavalu, initvalu[36]*1e3f);
    com[2] = kernel_cam(timeinst, initvalu, 76, parameter, 11, finavalu, initvalu[37]*1e3f);
}

#define fp float

inline fp sqr(fp x) { return x * x; }
inline fp cube(fp x) { return x * x * x; }

inline fp kernel_cam(fp timeinst,
                     __global const fp *initvalu,
                     int initvalu_offset,
                     __global const fp *parameter,
                     int parameter_offset,
                     __global fp *finavalu,
                     fp Ca) {
    (void)timeinst;

    const int b = initvalu_offset;
    const int p = parameter_offset;

    fp CaM             = initvalu[b + 0];
    fp Ca2CaM          = initvalu[b + 1];
    fp Ca4CaM          = initvalu[b + 2];
    fp CaMB            = initvalu[b + 3];
    fp Ca2CaMB         = initvalu[b + 4];
    fp Ca4CaMB         = initvalu[b + 5];
    fp Pb2             = initvalu[b + 6];
    fp Pb              = initvalu[b + 7];
    fp Pt              = initvalu[b + 8];
    fp Pt2             = initvalu[b + 9];
    fp Pa              = initvalu[b + 10];
    fp Ca4CaN          = initvalu[b + 11];
    fp CaMCa4CaN       = initvalu[b + 12];
    fp Ca2CaMCa4CaN    = initvalu[b + 13];
    fp Ca4CaMCa4CaN    = initvalu[b + 14];

    fp CaMtot          = parameter[p + 0];
    fp Btot            = parameter[p + 1];
    fp CaMKIItot       = parameter[p + 2];
    fp CaNtot          = parameter[p + 3];
    fp PP1tot          = parameter[p + 4];

    fp K = 135.0f;
    fp Mg = 1.0f;

    fp Kd02, Kd24;
    if (Mg <= 1.0f) {
        Kd02 = 0.0025f * (1.0f + K / 0.94f - Mg / 0.012f) * (1.0f + K / 8.1f + Mg / 0.022f);
        Kd24 = 0.128f * (1.0f + K / 0.64f + Mg / 0.0014f) * (1.0f + K / 13.0f - Mg / 0.153f);
    } else {
        Kd02 = 0.0025f * (1.0f + K / 0.94f - 1.0f / 0.012f + (Mg - 1.0f) / 0.060f) *
               (1.0f + K / 8.1f + 1.0f / 0.022f + (Mg - 1.0f) / 0.068f);
        Kd24 = 0.128f * (1.0f + K / 0.64f + 1.0f / 0.0014f + (Mg - 1.0f) / 0.005f) *
               (1.0f + K / 13.0f - 1.0f / 0.153f + (Mg - 1.0f) / 0.150f);
    }

    fp k20 = 10.0f;
    fp k02 = k20 / Kd02;
    fp k42 = 500.0f;
    fp k24 = k42 / Kd24;

    fp k0Boff = 0.0014f;
    fp k0Bon  = k0Boff / 0.2f;
    fp k2Boff = k0Boff / 100.0f;
    fp k2Bon  = k0Bon;
    fp k4Boff = k2Boff;
    fp k4Bon  = k0Bon;

    fp k20B = k20 / 100.0f;
    fp k02B = k02;
    fp k42B = k42;
    fp k24B = k24;

    fp kbi   = 2.2f;
    fp kib   = kbi / 33.5e-3f;
    fp kpp1  = 1.72f;
    fp Kmpp1 = 11.5f;
    fp kib2  = kib;
    fp kb2i  = kib2 * 5.0f;
    fp kb24  = k24;
    fp kb42  = k42 * 33.5e-3f / 5.0f;
    fp kta   = kbi / 1000.0f;
    fp kat   = kib;
    fp kt42  = k42 * 33.5e-6f / 5.0f;
    fp kt24  = k24;
    fp kat2  = kib;
    fp kt2a  = kib * 5.0f;

    fp kcanCaoff  = 1.0f;
    fp kcanCaon   = kcanCaoff / 0.5f;
    fp kcanCaM4on = 46.0f;
    fp kcanCaM4off = 0.0013f;
    fp kcanCaM2on  = kcanCaM4on;
    fp kcanCaM2off = 2508.0f * kcanCaM4off;
    fp kcanCaM0on  = kcanCaM4on;
    fp kcanCaM0off = 165.0f * kcanCaM2off;
    fp k02can      = k02;
    fp k20can      = k20 / 165.0f;
    fp k24can      = k24;
    fp k42can      = k20 / 2508.0f;

    fp rcn02 = k02 * sqr(Ca) * CaM - k20 * Ca2CaM;
    fp rcn24 = k24 * sqr(Ca) * Ca2CaM - k42 * Ca4CaM;

    fp B = Btot - CaMB - Ca2CaMB - Ca4CaMB;
    fp rcn02B = k02B * sqr(Ca) * CaMB - k20B * Ca2CaMB;
    fp rcn24B = k24B * sqr(Ca) * Ca2CaMB - k42B * Ca4CaMB;
    fp rcn0B  = k0Bon * CaM * B - k0Boff * CaMB;
    fp rcn2B  = k2Bon * Ca2CaM * B - k2Boff * Ca2CaMB;
    fp rcn4B  = k4Bon * Ca4CaM * B - k4Boff * Ca4CaMB;

    fp Ca2CaN   = CaNtot - Ca4CaN - CaMCa4CaN - Ca2CaMCa4CaN - Ca4CaMCa4CaN;
    fp rcnCa4CaN = kcanCaon * sqr(Ca) * Ca2CaN - kcanCaoff * Ca4CaN;
    fp rcn02CaN  = k02can * sqr(Ca) * CaMCa4CaN - k20can * Ca2CaMCa4CaN;
    fp rcn24CaN  = k24can * sqr(Ca) * Ca2CaMCa4CaN - k42can * Ca4CaMCa4CaN;
    fp rcn0CaN   = kcanCaM0on * CaM * Ca4CaN - kcanCaM0off * CaMCa4CaN;
    fp rcn2CaN   = kcanCaM2on * Ca2CaM * Ca4CaN - kcanCaM2off * Ca2CaMCa4CaN;
    fp rcn4CaN   = kcanCaM4on * Ca4CaM * Ca4CaN - kcanCaM4off * Ca4CaMCa4CaN;

    fp Pix = 1.0f - Pb2 - Pb - Pt - Pt2 - Pa;
    fp rcnCKib2  = kib2 * Ca2CaM * Pix - kb2i * Pb2;
    fp rcnCKb2b  = kb24 * sqr(Ca) * Pb2 - kb42 * Pb;
    fp rcnCKib   = kib * Ca4CaM * Pix - kbi * Pb;
    fp T         = Pb + Pt + Pt2 + Pa;
    fp kbt       = 0.055f * T + 0.0074f * sqr(T) + 0.015f * cube(T);
    fp rcnCKbt   = kbt * Pb - kpp1 * PP1tot * Pt / (Kmpp1 + CaMKIItot * Pt);
    fp rcnCKtt2  = kt42 * Pt - kt24 * sqr(Ca) * Pt2;
    fp rcnCKta   = kta * Pt - kat * Ca4CaM * Pa;
    fp rcnCKt2a  = kt2a * Pt2 - kat2 * Ca2CaM * Pa;
    fp rcnCKt2b2 = kpp1 * PP1tot * Pt2 / (Kmpp1 + CaMKIItot * Pt2);
    fp rcnCKai   = kpp1 * PP1tot * Pa / (Kmpp1 + CaMKIItot * Pa);

    fp dCaM          = 1.0e-3f * (-rcn02 - rcn0B - rcn0CaN);
    fp dCa2CaM       = 1.0e-3f * (rcn02 - rcn24 - rcn2B - rcn2CaN + CaMKIItot * (-rcnCKib2 + rcnCKt2a));
    fp dCa4CaM       = 1.0e-3f * (rcn24 - rcn4B - rcn4CaN + CaMKIItot * (-rcnCKib + rcnCKta));
    fp dCaMB         = 1.0e-3f * (rcn0B - rcn02B);
    fp dCa2CaMB      = 1.0e-3f * (rcn02B + rcn2B - rcn24B);
    fp dCa4CaMB      = 1.0e-3f * (rcn24B + rcn4B);
    fp dPb2          = 1.0e-3f * (rcnCKib2 - rcnCKb2b + rcnCKt2b2);
    fp dPb           = 1.0e-3f * (rcnCKib + rcnCKb2b - rcnCKbt);
    fp dPt           = 1.0e-3f * (rcnCKbt - rcnCKta - rcnCKtt2);
    fp dPt2          = 1.0e-3f * (rcnCKtt2 - rcnCKt2a - rcnCKt2b2);
    fp dPa           = 1.0e-3f * (rcnCKta + rcnCKt2a - rcnCKai);
    fp dCa4CaN       = 1.0e-3f * (rcnCa4CaN - rcn0CaN - rcn2CaN - rcn4CaN);
    fp dCaMCa4CaN    = 1.0e-3f * (rcn0CaN - rcn02CaN);
    fp dCa2CaMCa4CaN = 1.0e-3f * (rcn2CaN + rcn02CaN - rcn24CaN);
    fp dCa4CaMCa4CaN = 1.0e-3f * (rcn4CaN + rcn24CaN);

    finavalu[b + 0]  = dCaM;
    finavalu[b + 1]  = dCa2CaM;
    finavalu[b + 2]  = dCa4CaM;
    finavalu[b + 3]  = dCaMB;
    finavalu[b + 4]  = dCa2CaMB;
    finavalu[b + 5]  = dCa4CaMB;
    finavalu[b + 6]  = dPb2;
    finavalu[b + 7]  = dPb;
    finavalu[b + 8]  = dPt;
    finavalu[b + 9]  = dPt2;
    finavalu[b + 10] = dPa;
    finavalu[b + 11] = dCa4CaN;
    finavalu[b + 12] = dCaMCa4CaN;
    finavalu[b + 13] = dCa2CaMCa4CaN;
    finavalu[b + 14] = dCa4CaMCa4CaN;

    fp JCa = 1.0e-3f * (2.0f * CaMKIItot * (rcnCKtt2 - rcnCKb2b) -
              2.0f * (rcn02 + rcn24 + rcn02B + rcn24B + rcnCa4CaN + rcn02CaN + rcn24CaN));

    return JCa;
}

inline void kernel_ecc(fp timeinst,
                       __global const fp *initvalu,
                       int initvalu_offset,
                       __global const fp *parameter,
                       int parameter_offset,
                       __global fp *finavalu) {
    const int b = initvalu_offset;
    const int p = parameter_offset;

    fp initvalu_1  = initvalu[b + 0];
    fp initvalu_2  = initvalu[b + 1];
    fp initvalu_3  = initvalu[b + 2];
    fp initvalu_4  = initvalu[b + 3];
    fp initvalu_5  = initvalu[b + 4];
    fp initvalu_6  = initvalu[b + 5];
    fp initvalu_7  = initvalu[b + 6];
    fp initvalu_8  = initvalu[b + 7];
    fp initvalu_9  = initvalu[b + 8];
    fp initvalu_10 = initvalu[b + 9];
    fp initvalu_11 = initvalu[b + 10];
    fp initvalu_12 = initvalu[b + 11];
    fp initvalu_13 = initvalu[b + 12];
    fp initvalu_14 = initvalu[b + 13];
    fp initvalu_15 = initvalu[b + 14];
    fp initvalu_16 = initvalu[b + 15];
    fp initvalu_17 = initvalu[b + 16];
    fp initvalu_18 = initvalu[b + 17];
    fp initvalu_19 = initvalu[b + 18];
    fp initvalu_20 = initvalu[b + 19];
    fp initvalu_21 = initvalu[b + 20];
    fp initvalu_22 = initvalu[b + 21];
    fp initvalu_23 = initvalu[b + 22];
    fp initvalu_24 = initvalu[b + 23];
    fp initvalu_25 = initvalu[b + 24];
    fp initvalu_26 = initvalu[b + 25];
    fp initvalu_27 = initvalu[b + 26];
    fp initvalu_28 = initvalu[b + 27];
    fp initvalu_29 = initvalu[b + 28];
    fp initvalu_30 = initvalu[b + 29];
    fp initvalu_31 = initvalu[b + 30];
    fp initvalu_32 = initvalu[b + 31];
    fp initvalu_33 = initvalu[b + 32];
    fp initvalu_34 = initvalu[b + 33];
    fp initvalu_35 = initvalu[b + 34];
    fp initvalu_36 = initvalu[b + 35];
    fp initvalu_37 = initvalu[b + 36];
    fp initvalu_38 = initvalu[b + 37];
    fp initvalu_39 = initvalu[b + 38];
    fp initvalu_40 = initvalu[b + 39];
    fp initvalu_41 = initvalu[b + 40];
    fp initvalu_42 = initvalu[b + 41];
    fp initvalu_43 = initvalu[b + 42];
    fp initvalu_44 = initvalu[b + 43];
    fp initvalu_45 = initvalu[b + 44];
    fp initvalu_46 = initvalu[b + 45];

    fp parameter_1 = parameter[p + 0];

    fp pi = 3.1416f;

    fp R = 8314.0f;
    fp Frdy = 96485.0f;
    fp Temp = 310.0f;
    fp FoRT = Frdy / R / Temp;
    fp Cmem = 1.3810e-10f;
    fp Qpow = (Temp - 310.0f) / 10.0f;

    fp cellLength = 100.0f;
    fp cellRadius = 10.25f;
    fp junctionLength = 160e-3f;
    fp junctionRadius = 15e-3f;
    fp distSLcyto = 0.45f;
    fp distJuncSL = 0.5f;
    fp DcaJuncSL = 1.64e-6f;
    fp DcaSLcyto = 1.22e-6f;
    fp DnaJuncSL = 1.09e-5f;
    fp DnaSLcyto = 1.79e-5f;
    fp Vcell = pi * sqr(cellRadius) * cellLength * 1e-15f;
    fp Vmyo = 0.65f * Vcell;
    fp Vsr = 0.035f * Vcell;
    fp Vsl = 0.02f * Vcell;
    fp Vjunc = 0.0539f * 0.01f * Vcell;
    fp SAjunc = 20150.0f * pi * 2.0f * junctionLength * junctionRadius;
    fp SAsl = pi * 2.0f * cellRadius * cellLength;
    fp J_ca_juncsl = 1.0f / 1.2134e12f;
    fp J_ca_slmyo = 1.0f / 2.68510e11f;
    fp J_na_juncsl = 1.0f / (1.6382e12f / 3.0f * 100.0f);
    fp J_na_slmyo = 1.0f / (1.8308e10f / 3.0f * 100.0f);

    (void)distSLcyto;
    (void)distJuncSL;
    (void)DcaJuncSL;
    (void)DcaSLcyto;
    (void)DnaJuncSL;
    (void)DnaSLcyto;
    (void)SAjunc;
    (void)SAsl;

    fp Fjunc = 0.11f;
    fp Fsl = 1.0f - Fjunc;
    fp Fjunc_CaL = 0.9f;
    fp Fsl_CaL = 1.0f - Fjunc_CaL;

    fp Cli = 15.0f;
    fp Clo = 150.0f;
    fp Ko = 5.4f;
    fp Nao = 140.0f;
    fp Cao = 1.8f;
    fp Mgi = 1.0f;

    fp ena_junc = (1.0f / FoRT) * log(Nao / initvalu_32);
