    finavalu[b + 32] = -I_Na_tot_sl * Cmem * oneovervsl / Frdy +
                       J_na_juncsl * oneovervsl * (initvalu_32 - initvalu_33) +
                       J_na_slmyo * oneovervsl * (initvalu_34 - initvalu_33) - finavalu[b + 17];
    finavalu[b + 33] = J_na_slmyo / Vmyo * (initvalu_33 - initvalu_34);

    fp I_K_tot = I_to + I_kr + I_ks + I_ki - 2.0f * I_nak + I_CaK + I_kp;
    finavalu[b + 34] = 0.0f;

    fp I_Ca_tot_junc = I_Ca_junc + I_cabk_junc + I_pca_junc - 2.0f * I_ncx_junc;
    fp I_Ca_tot_sl = I_Ca_sl + I_cabk_sl + I_pca_sl - 2.0f * I_ncx_sl;
    finavalu[b + 35] = -I_Ca_tot_junc * Cmem / (Vjunc * 2.0f * Frdy) + J_ca_juncsl / Vjunc * (initvalu_37 - initvalu_36)
                     - J_CaB_junction + J_SRCarel * Vsr / Vjunc + J_SRleak * Vmyo / Vjunc;
    finavalu[b + 36] = -I_Ca_tot_sl * Cmem / (Vsl * 2.0f * Frdy) + J_ca_juncsl / Vsl * (initvalu_36 - initvalu_37)
                     + J_ca_slmyo / Vsl * (initvalu_38 - initvalu_37) - J_CaB_sl;
    finavalu[b + 37] = -J_serca - J_CaB_cytosol + J_ca_slmyo / Vmyo * (initvalu_37 - initvalu_38);

    fp junc_sl = J_ca_juncsl / Vsl * (initvalu_36 - initvalu_37);
    fp sl_junc = J_ca_juncsl / Vjunc * (initvalu_37 - initvalu_36);
    fp sl_myo = J_ca_slmyo / Vsl * (initvalu_38 - initvalu_37);
    fp myo_sl = J_ca_slmyo / Vmyo * (initvalu_37 - initvalu_38);
    (void)junc_sl;
    (void)sl_junc;
    (void)sl_myo;
    (void)myo_sl;

    int state = 1;
    fp I_app, V_hold, V_test, V_clamp, R_clamp;
    switch (state) {
        case 0:
            I_app = 0.0f;
            break;
        case 1:
            if (fmod(timeinst, parameter_1) <= 5.0f) {
                I_app = 9.5f;
            } else {
                I_app = 0.0f;
            }
            break;
        case 2:
            V_hold = -55.0f;
            V_test = 0.0f;
            if ((timeinst > 0.5f) & (timeinst < 200.5f)) {
                V_clamp = V_test;
            } else {
                V_clamp = V_hold;
            }
            R_clamp = 0.04f;
            I_app = (V_clamp - initvalu_39) / R_clamp;
            break;
        default:
            I_app = 0.0f;
            break;
    }

    fp I_Na_tot = I_Na_tot_junc + I_Na_tot_sl;
    fp I_Cl_tot = I_ClCa + I_Clbk;
    fp I_Ca_tot = I_Ca_tot_junc + I_Ca_tot_sl;
    fp I_tot = I_Na_tot + I_Cl_tot + I_Ca_tot + I_K_tot;
    finavalu[b + 38] = -(I_tot - I_app);

    finavalu[b + 40] = 0.0f;
    finavalu[b + 41] = 0.0f;

    (void)initvalu_41;
    (void)initvalu_42;
    (void)initvalu_43;
    (void)initvalu_44;
    (void)initvalu_45;
    (void)initvalu_46;
}

__kernel void kernel_gpu_opencl(fp timeinst,
                                __global const fp *initvalu,
                                __global fp *finavalu,
                                __global const fp *parameter,
                                __global fp *com) {
    int gid = get_global_id(0);

    if (gid == 0) {
        kernel_ecc(timeinst, initvalu, 0, parameter, 0, finavalu);
    } else if (gid == 1) {
        com[0] = kernel_cam(timeinst, initvalu, 46, parameter, 1, finavalu, initvalu[35] * 1.0e3f);
    } else if (gid == 2) {
        com[1] = kernel_cam(timeinst, initvalu, 61, parameter, 6, finavalu, initvalu[36] * 1.0e3f);
    } else if (gid == 3) {
        com[2] = kernel_cam(timeinst, initvalu, 76, parameter, 11, finavalu, initvalu[37] * 1.0e3f);
    }
}

#define fp float
#define EQUATIONS 91
#define PARAMETERS 18

inline fp sqr(fp x) { return x * x; }
