                                __global double *partial_sums,
                                __local double *buffer) {
    int x = get_global_id(0);
    (void)CDF;
    (void)u;
    (void)buffer;

    if (x >= Nparticles)
        return;

    arrayX[x] = xj[x] + 1.0 + 5.0 * pf_randn(seed, x);
    arrayY[x] = yj[x] + -2.0 + 2.0 * pf_randn(seed, x);

    double like = 0.0;
    for (int y = 0; y < countOnes; y++) {
        int indX = (int)pf_roundDouble(arrayX[x]) + objxy[y * 2 + 1];
        int indY = (int)pf_roundDouble(arrayY[x]) + objxy[y * 2];
        int idx = abs(indX * IszY * Nfr + indY * Nfr + k);
        if (idx >= max_size)
            idx = 0;
