    int gid = get_global_id(0);
    if (gid != 0)
        return;

    double sumWeights = partial_sums[0];
    if (sumWeights == 0.0)
        sumWeights = 1.0;

    for (int x = 0; x < Nparticles; x++) {
        weights[x] = weights[x] / sumWeights;
    }

    if (Nparticles > 0) {
        CDF[0] = weights[0];
        for (int x = 1; x < Nparticles; x++) {
            CDF[x] = weights[x] + CDF[x - 1];
        }

        double u1 = (1.0 / (double)Nparticles) * pf_randu(seed, 0);
