                                __global double *arrayY,
                                __global double *CDF,
                                __global double *u,
                                __global double *xj,
                                __global double *yj,
                                __global double *weights,
                                int Nparticles) {
    int j = get_global_id(0);
    if (j >= Nparticles)
        return;

    int i = pf_findIndex(CDF, Nparticles, u[j]);
    if (i == -1)
        i = Nparticles - 1;

    xj[j] = arrayX[i];
    yj[j] = arrayY[i];
    weights[j] = 1.0 / ((double)Nparticles);
