                             const int border,
                             const int HALO,
                             __local int *prev,
                             __local int *result,
                             __global int *outputBuffer)
{
    const int tx = (int)get_local_id(0);
    const int bx = (int)get_group_id(0);
    const int localSize = (int)get_local_size(0);

    const int small_block_cols = localSize - iteration * HALO * 2;
    if (small_block_cols <= 0) {
