                             __global fp *d_sums2)
{
    size_t ei = get_global_id(0);

    if ((long)ei < d_Ne) {
        fp val = d_I[ei];
        d_sums[ei] = val;
        d_sums2[ei] = val * val;
    }
}

__kernel void reduce_kernel(long d_Ne,
                            long d_no,
                            int d_mul,
                            __global fp *d_sums,
                            __global fp *d_sums2,
                            int d_blocks2_work_size)
{
    size_t bx = get_group_id(0);
    size_t tx = get_local_id(0);
    size_t lsize = get_local_size(0);

    (void)d_Ne;
    (void)d_blocks2_work_size;

    if (tx == 0) {
        long start = (long)bx * (long)lsize;
        if (start < d_no) {
            long end = start + (long)lsize;
            if (end > d_no) {
                end = d_no;
            }

            fp sum = (fp)0.0f;
            fp sum2 = (fp)0.0f;

            for (long i = start; i < end; i++) {
                long idx = i * (long)d_mul;
                fp v = d_sums[idx];
                fp v2 = d_sums2[idx];
                sum += v;
                sum2 += v2;
            }

            long out_idx = (long)bx * (long)d_mul * (long)lsize;
            d_sums[out_idx] = sum;
            d_sums2[out_idx] = sum2;
        }
    }
}

__kernel void srad_kernel(fp lambda,
                          int Nr,
                          int Nc,
                          long Ne,
                          __global int *d_iN,
                          __global int *d_iS,
                          __global int *d_jE,
                          __global int *d_jW,
                          __global fp *d_dN,
                          __global fp *d_dS,
                          __global fp *d_dW,
                          __global fp *d_dE,
                          fp q0sqr,
                          __global fp *d_c,
                          __global fp *d_I)
{
    size_t ei = get_global_id(0);

    (void)lambda;

    if ((long)ei < Ne) {
        int row = (int)(ei / (size_t)Nc);
        int col = (int)(ei % (size_t)Nc);

        fp Jc = d_I[ei];

        int iN = d_iN[row];
        int iS = d_iS[row];
        int jW = d_jW[col];
        int jE = d_jE[col];

        d_dN[ei] = d_I[iN * Nc + col] - Jc;
        d_dS[ei] = d_I[iS * Nc + col] - Jc;
        d_dW[ei] = d_I[row * Nc + jW] - Jc;
        d_dE[ei] = d_I[row * Nc + jE] - Jc;

        fp G2 = (d_dN[ei] * d_dN[ei] +
                 d_dS[ei] * d_dS[ei] +
                 d_dW[ei] * d_dW[ei] +
                 d_dE[ei] * d_dE[ei]) / (Jc * Jc);

        fp L = (d_dN[ei] + d_dS[ei] + d_dW[ei] + d_dE[ei]) / Jc;

        fp num = (fp)0.5f * G2 - (fp)0.0625f * L * L;
        fp den = (fp)1.0f + (fp)0.25f * L;
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * ((fp)1.0f + q0sqr));
        fp c = (fp)1.0f / ((fp)1.0f + den);

        if (c < (fp)0.0f) {
            c = (fp)0.0f;
        } else if (c > (fp)1.0f) {
            c = (fp)1.0f;
        }

        d_c[ei] = c;
    }
}

__kernel void srad2_kernel(fp lambda,
                           int Nr,
                           int Nc,
                           long Ne,
                           __global int *d_iN,
                           __global int *d_iS,
                           __global int *d_jE,
                           __global int *d_jW,
                           __global fp *d_dN,
                           __global fp *d_dS,
                           __global fp *d_dW,
                           __global fp *d_dE,
                           __global fp *d_c,
                           __global fp *d_I)
{
    size_t ei = get_global_id(0);

    (void)d_iN;
    (void)d_jW;

    if ((long)ei < Ne) {
        int row = (int)(ei / (size_t)Nc);
        int col = (int)(ei % (size_t)Nc);

        fp cN = d_c[ei];
        fp cS = d_c[d_iS[row] * Nc + col];
        fp cW = d_c[ei];
        fp cE = d_c[row * Nc + d_jE[col]];

        fp D = cN * d_dN[ei] +
               cS * d_dS[ei] +
               cW * d_dW[ei] +
               cE * d_dE[ei];

        d_I[ei] = d_I[ei] + (fp)0.25f * lambda * D;
    }
}

__kernel void compress_kernel(long d_Ne,
                              __global fp *d_I)
{
    size_t ei = get_global_id(0);

    if ((long)ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * (fp)255.0f;
    }
}

